import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (with fee) ---
  it("single sword (no modifiers, first contract) → premium 115 G (100 base + 10 first ins + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("single amulet (no modifiers, first contract) → premium 71 G (60 + 6 + 5)");
  it.todo("single staff (no modifiers, first contract) → premium 93 G (80 + 8 + 5)");
  it.todo("single potion (no modifiers, first contract) → premium 49 G (40 + 4 + 5)");

  // --- Components base premiums ---
  it.todo("2 runes → base 50 G");
  it.todo("3 runes (block) → base 60 G");
  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
  it.todo("7 runes → base 175 G");

  // --- Alike components ---
  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");

  // --- Item-specific modifiers ---
  it.todo("cursed sword (first contract) → cursed surcharge 50% applies");
  it.todo("sword enchantment 5 (first contract) → high-enchantment surcharge 30% applies");
  it.todo("sword enchantment 4 (first contract) → no high-enchantment surcharge");
  it.todo("cursed sword enchantment 5 → both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer 2 years → loyalty discount applies");
  it.todo("customer 1 year → no loyalty discount");
  it.todo("second contract → follow-up discount 15% applies");

  // --- Modifier scope (item vs policy) ---
  it.todo("cursed sword + plain amulet → cursed surcharge applies to sword only; policy base 160, after curse 210 before fee");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G → rounded UP to 198 G");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword → premium 165 G");
  it.todo("long-standing customer's second contract with cursed enchanted sword → premium 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("steel sword enchantment 3, damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to rune (insurance 250 G), damage 200 G → payout 100 G");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: dragon + enchantment ---
  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (deductible per item)");

  // --- Payout rounding ---
  it.todo("payout calc yielding 350.5 G → rounded DOWN to 350 G");

  // --- Multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two swords damaged separately → each entry has own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI rejects (non-zero exit)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword (cap 2000), second claim 1500 after 1500 → payout 600, remainingCap 0");

  // --- Edge cases ---
  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
  it.todo("claim references item not in policy → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
});

