export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const EPSILON = 1e-9;

const roundUp = (n: number): number => Math.ceil(n - EPSILON);

const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
  rune: 25,
  moonstone: 25,
};

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  ...MAIN_ITEM_BASE_PREMIUMS,
  ...COMPONENT_BASE_PREMIUMS,
};

const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const withFirstInsuranceSurcharge = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;

const componentGroupBase = (count: number, unitBase: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_BASE;
  return count * unitBase;
};

const quotePremium = (items: Item[]): number => {
  let policyTotal = 0;
  const componentCounts = new Map<string, number>();

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      policyTotal += withFirstInsuranceSurcharge(itemBase(item.type));
    }
  }

  for (const [type, count] of componentCounts) {
    const groupBase = componentGroupBase(count, itemBase(type));
    policyTotal += withFirstInsuranceSurcharge(groupBase);
  }

  return roundUp(policyTotal) + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

