import { describe, it, expect } from "vitest";
import { processScenario, type Item } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (with fee) ---
  it("single sword (no modifiers, first contract) → premium 115 G (100 base + 10 first ins + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet (no modifiers, first contract) → premium 71 G (60 + 6 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff (no modifiers, first contract) → premium 93 G (80 + 8 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion (no modifiers, first contract) → premium 49 G (40 + 4 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // --- Components base premiums ---
  it("2 runes → base 50 G (premium 60 G with first ins + fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes (block) → base 60 G (premium 71 with first ins + fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes → base 100 G (premium 115 with first ins + fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes → base 175 G (premium 198 with first ins + fee, rounded up)", () => {
    const items: Item[] = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });

  // --- Alike components ---
  it("2 runes + 1 moonstone → base 75 G (premium 88 with first ins + fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones → base 120 G (premium 137)", () => {
    const items: Item[] = [
      ...Array.from({ length: 3 }, () => ({ type: "rune" })),
      ...Array.from({ length: 3 }, () => ({ type: "moonstone" })),
    ];
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // --- Item-specific modifiers ---
  it("cursed sword (first contract) → premium 165 G (100 base + 50 curse + 10 first ins + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it("sword enchantment 5 (first contract) → premium 145 (100 + 30 + 10 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it("sword enchantment 4 (first contract) → premium 115 (no high-ench surcharge)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("cursed sword enchantment 5 → premium 195 (both surcharges apply)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 195 });
  });

  // --- Policy-wide modifiers ---
  it("customer 2 years → loyalty discount applies, sword premium 95 (100 + 10 - 20 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it("customer 1 year → no loyalty discount, sword premium 115", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 1 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("second contract → follow-up discount 15% applies");

  // --- Modifier scope (item vs policy) ---
  it.todo("cursed sword + plain amulet → cursed surcharge applies to sword only; policy base 160, after curse 210 before fee");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G → rounded UP to 198 G");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword → premium 165 G");
  it.todo("long-standing customer's second contract with cursed enchanted sword → premium 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("steel sword enchantment 3, damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to rune (insurance 250 G), damage 200 G → payout 100 G");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: dragon + enchantment ---
  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (deductible per item)");

  // --- Payout rounding ---
  it.todo("payout calc yielding 350.5 G → rounded DOWN to 350 G");

  // --- Multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two swords damaged separately → each entry has own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI rejects (non-zero exit)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword (cap 2000), second claim 1500 after 1500 → payout 600, remainingCap 0");

  // --- Edge cases ---
  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
  it.todo("claim references item not in policy → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
});

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const EPSILON = 1e-9;

const roundUp = (n: number): number => Math.ceil(n - EPSILON);

const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
  rune: 25,
  moonstone: 25,
};

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  ...MAIN_ITEM_BASE_PREMIUMS,
  ...COMPONENT_BASE_PREMIUMS,
};

const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;

const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;

const componentGroupBase = (count: number, unitBase: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_BASE;
  return count * unitBase;
};

const itemSurchargeRate = (item: Item): number => {
  let rate = 0;
  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return rate;
};

const itemSurcharge = (item: Item, base: number): number =>
  base * itemSurchargeRate(item);

const policyModifierRate = (customer: Customer): number => {
  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
    rate -= LOYALTY_DISCOUNT_RATE;
  }
  return rate;
};

const quotePremium = (items: Item[], customer: Customer): number => {
  let policyBase = 0;
  let itemSurchargeTotal = 0;
  const componentCounts = new Map<string, number>();

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      const base = itemBase(item.type);
      policyBase += base;
      itemSurchargeTotal += itemSurcharge(item, base);
    }
  }

  for (const [type, count] of componentCounts) {
    const groupBase = componentGroupBase(count, itemBase(type));
    policyBase += groupBase;
  }

  const policyModifierTotal = policyBase * policyModifierRate(customer);
  const total = policyBase + itemSurchargeTotal + policyModifierTotal;
  return roundUp(total) + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items, scenario.customer) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

