const countByType = <T extends { type?: string } | Item | Damage>(
  entries: { itemType?: string; type?: string }[] | Item[],
): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const entry of entries as { itemType?: string; type?: string }[]) {
    const key = entry.itemType ?? entry.type ?? "";
    counts.set(key, (counts.get(key) ?? 0) + 1);
  }
  return counts;
};

const validateClaimDamageCountsFitPolicy = (scenario: Scenario): void => {
  for (const step of scenario.steps.filter(isClaimStep)) {
